Consider the following code:

class Base { public: virtual void show() { cout << "Base"; } };
class Derived : public Base { public: void show() { cout << "Derived"; } };

Base* ptr = new Derived();
ptr->show();

What will be the output?

Consider this code:

class A { public: virtual void f() { cout << 1; } };
class B : public A { public: void f() override { cout << 2; } };
class C : public B { public: void f() { cout << 3; } };

A* arr[2] = { new B(), new C() };
for (int i = 0; i < 2; i++) arr[i]->f();

What is the output?

Given:

class Shape { public: virtual void draw() = 0; virtual ~Shape() {} };
class Circle : public Shape { public: void draw() { cout << "Circle"; } };
class Square : public Shape { public: void draw() { cout << "Square"; } };

void display(Shape* s) { s->draw(); }

Circle c; Square s;
Shape* shapes[2] = { &c, &s };
display(shapes[0]);
display(shapes[1]);

What is the output?
